                    if is_failed_connection_cleanup:
                        error_message += "Connection timeout."
                        raise UserError(error_message) from timeout_error
                    else:
                        logger.warning(
                            f"Timeout error during cleanup of MCP server '{self.name}': {timeout_error}"  # noqa: E501
                        )
